                </div>
              </div>
            </dl>
          </DashboardCard>

          {/* Videos Placeholder */}
          <DashboardCard className="p-6">
            <SectionTitle
              title="الفيديوهات"
              action={
                <Button variant="outline" size="sm" disabled>
                  <Plus className="h-4 w-4" />
                  رفع فيديو
                </Button>
              }
            />
            <div className="mt-4">
              {statistics.videos > 0 ? (
                <p className="text-sm text-muted-foreground">
                  {statistics.videos} فيديو — قيد التطوير
