                    </div>
                    <div className="pb-2">
                      <p className="text-sm font-medium">
                        {ACTIVITY_LABELS[entry.type] ?? entry.type}
                      </p>
                      <p className="text-xs text-muted-foreground">
                        {formatDateTime(entry.createdAt)}
                      </p>
                    </div>
                  </li>
                ))}
              </ol>
            )}
          </DashboardCard>
        </div>
      </div>
    </div>
  );
}
